def dedupe(lst):
    """Remove duplicates, preserving order. Must work with unhashable items."""
    seen = set()
    result = []
    for item in lst:
        if item not in seen:
            seen.add(item)  # Bug: fails on unhashable (dicts, lists)
            result.append(item)
    return result

