def flatten(lst):
    """Recursively flatten nested lists."""
    result = []
    for item in lst:
        if isinstance(item, list):
            result.extend(flatten(item))
        else:
            result.append(item)
    return result

# Bug: doesn't handle tuples or other iterables
# Also: doesn't handle deeply nested empty lists correctly

